A minimal first production slice is a single-module implementation that does two things in a fixed order: normalize and validate untrusted input into a trusted internal shape, then compute the quote with integer-only arithmetic.

```ts
export type QuoteRequest = {
  customerKind: "retail" | "trade";
  subtotalCents: number;
  destination: "domestic" | "international";
  expedited?: boolean;
};

export type Quote = {
  subtotalCents: number;
  discountCents: number;
  shippingCents: number;
  totalCents: number;
};

export class QuoteInputError extends Error {
  readonly field: string;

  constructor(field: string, message = `Invalid field: ${field}`) {
    super(message);
    this.name = "QuoteInputError";
    this.field = field;
  }
}

function isRecord(value: unknown): value is Record<string, unknown> {
  return typeof value === "object" && value !== null;
}

function requireEnum<T extends string>(
  obj: Record<string, unknown>,
  field: string,
  allowed: readonly T[],
): T {
  const value = obj[field];
  if (typeof value !== "string" || !allowed.includes(value as T)) {
    throw new QuoteInputError(field);
  }
  return value as T;
}

function requireNonnegativeInteger(
  obj: Record<string, unknown>,
  field: string,
): number {
  const value = obj[field];
  if (
    typeof value !== "number" ||
    !Number.isInteger(value) ||
    value < 0
  ) {
    throw new QuoteInputError(field);
  }
  return value;
}

function requireOptionalBoolean(
  obj: Record<string, unknown>,
  field: string,
): boolean {
  const value = obj[field];
  if (value === undefined) {
    return false;
  }
  if (typeof value !== "boolean") {
    throw new QuoteInputError(field);
  }
  return value;
}

function parseQuoteRequest(input: unknown): QuoteRequest {
  if (!isRecord(input)) {
    throw new QuoteInputError("input", "Input must be an object");
  }

  return {
    customerKind: requireEnum(input, "customerKind", ["retail", "trade"]),
    subtotalCents: requireNonnegativeInteger(input, "subtotalCents"),
    destination: requireEnum(input, "destination", ["domestic", "international"]),
    expedited: requireOptionalBoolean(input, "expedited"),
  };
}

export function quoteOrder(input: unknown): Quote {
  const request = parseQuoteRequest(input);

  const discountCents =
    request.customerKind === "trade"
      ? Math.floor(request.subtotalCents * 0.1)
      : 0;

  const baseShippingCents =
    request.destination === "domestic" ? 500 : 1500;

  const shippingCents =
    baseShippingCents + (request.expedited ? 700 : 0);

  const totalCents =
    request.subtotalCents - discountCents + shippingCents;

  return {
    subtotalCents: request.subtotalCents,
    discountCents,
    shippingCents,
    totalCents,
  };
}
```

Tests should stay table-driven and verify both boundary validation and arithmetic:

```ts
import { describe, expect, it } from "vitest";
import { QuoteInputError, quoteOrder } from "./quoteOrder";

describe("quoteOrder", () => {
  it("quotes a retail domestic order", () => {
    expect(
      quoteOrder({
        customerKind: "retail",
        subtotalCents: 2000,
        destination: "domestic",
      }),
    ).toEqual({
      subtotalCents: 2000,
      discountCents: 0,
      shippingCents: 500,
      totalCents: 2500,
    });
  });

  it("quotes a trade international expedited order", () => {
    expect(
      quoteOrder({
        customerKind: "trade",
        subtotalCents: 1999,
        destination: "international",
        expedited: true,
      }),
    ).toEqual({
      subtotalCents: 1999,
      discountCents: 199,
      shippingCents: 2200,
      totalCents: 4000,
    });
  });

  it("defaults expedited to false", () => {
    expect(
      quoteOrder({
        customerKind: "trade",
        subtotalCents: 1000,
        destination: "domestic",
      }),
    ).toEqual({
      subtotalCents: 1000,
      discountCents: 100,
      shippingCents: 500,
      totalCents: 1400,
    });
  });

  it.each([
    [null, "input"],
    [{}, "customerKind"],
    [{ customerKind: "vip", subtotalCents: 100, destination: "domestic" }, "customerKind"],
    [{ customerKind: "retail", subtotalCents: -1, destination: "domestic" }, "subtotalCents"],
    [{ customerKind: "retail", subtotalCents: 12.5, destination: "domestic" }, "subtotalCents"],
    [{ customerKind: "retail", subtotalCents: 100, destination: "mars" }, "destination"],
    [{ customerKind: "retail", subtotalCents: 100, destination: "domestic", expedited: "yes" }, "expedited"],
  ])("rejects malformed input %#", (input, field) => {
    expect(() => quoteOrder(input)).toThrowError(QuoteInputError);
    expect(() => quoteOrder(input)).toThrowError(
      expect.objectContaining({ field }),
    );
  });
});
```

Construction choices:

- Input validation: treat `input` as hostile and convert `unknown` to a trusted `QuoteRequest` once, at the boundary. That keeps the computation path free of repeated type checks.
- Data meaning: `subtotalCents` is a money amount in cents, so nonnegative integer validation is part of the domain, not just type hygiene.
- Arithmetic: keep everything in integer cents. `Math.floor(subtotal * 0.1)` implements the required trade discount rounding-down rule explicitly.
- Control shape: one parser plus one straight-line calculator is the smallest shape that is easy to verify. No premature abstractions for pricing rules yet.
- Error semantics: `QuoteInputError` carries the invalid field name so callers can map it back to HTTP 400 responses deterministically.
- Smallest verifiable increment: first ship support for valid object parsing, one retail happy path, one trade+expedited happy path, and one invalid case per field. That covers the full required behavior without dragging in HTTP, storage, or cross-module concerns.

Residual note: if this grows, the next safe extraction is a pure `parseQuoteRequest` boundary and a pure `computeQuote(request)` calculator, but for the first slice they can remain in one module.
